async function run(input) {
  var betrag = Number((input && input.betrag) || 0);
  var satz = (input && input.satz != null) ? Number(input.satz) : 19;
  var modus = String((input && input.modus) || 'netto2brutto').toLowerCase();
  function r2(x) { return Math.round((x + Number.EPSILON) * 100) / 100; }
  var f = satz / 100;
  var netto, brutto, mwstBetrag;
  if (modus === 'brutto2netto') {
    brutto = betrag;
    netto = brutto / (1 + f);
    mwstBetrag = brutto - netto;
  } else {
    // netto2brutto and mwst both treat betrag as netto
    netto = betrag;
    mwstBetrag = netto * f;
    brutto = netto + mwstBetrag;
  }
  return { netto: r2(netto), brutto: r2(brutto), mwstBetrag: r2(mwstBetrag), satz: satz, modus: modus };
}
